"""
title: MCP Manager Control
description: Manage json-mcp-manager via MCP — list, start, stop, restart instances, view logs, upload tools, edit code and more. Security levels are enforced server-side.
author: Torsten Feustel
version: 0.0.4
license: MIT
"""
import json
import httpx
from pydantic import BaseModel, Field


class Tools:
    class Valves(BaseModel):
        manager_url: str = Field(
            default="http://127.0.0.1:7860",
            description="Base URL of the json-mcp-manager instance"
        )
        auth_token: str = Field(
            default="",
            description="Bearer token for manager authentication (leave empty if no auth)"
        )
        allow_list_instances: bool = Field(default=True, description="Allow: list all instances")
        allow_get_instance: bool = Field(default=True, description="Allow: get instance details")
        allow_start: bool = Field(default=True, description="Allow: start an instance")
        allow_stop: bool = Field(default=True, description="Allow: stop an instance")
        allow_restart: bool = Field(default=True, description="Allow: restart an instance")
        allow_reinstall: bool = Field(default=True, description="Allow: reinstall dependencies")
        allow_install_log: bool = Field(default=True, description="Allow: read install log")
        allow_runtime_log: bool = Field(default=True, description="Allow: read runtime log")
        allow_get_config: bool = Field(default=True, description="Allow: get instance config")
        allow_get_settings: bool = Field(default=True, description="Allow: get manager settings")
        allow_get_code: bool = Field(default=True, description="Allow: read tool source code")
        allow_save_code: bool = Field(default=True, description="Allow: save/edit tool source code")
        allow_validate_code: bool = Field(default=True, description="Allow: validate tool code")
        allow_export_tool: bool = Field(default=True, description="Allow: export tool as JSON")
        allow_delete: bool = Field(default=False, description="Allow: delete an instance (disabled by default)")
        allow_manager_restart: bool = Field(default=False, description="Allow: restart the manager process (disabled by default)")
        allow_get_template: bool = Field(default=True, description="Allow: get the tool code template")
        allow_upload: bool = Field(default=True, description="Allow: upload and install a new tool")
        allow_create_tool: bool = Field(default=True, description="Allow: create a new tool from raw code")
        allow_update_values: bool = Field(default=True, description="Allow: update instance valve values")
        allow_update_dependencies: bool = Field(default=True, description="Allow: update/reinstall instance dependencies")
        allow_update_venv: bool = Field(default=True, description="Allow: move an instance to another venv")

    def __init__(self):
        self.valves = self.Valves()

    def _denied(self, valve_name: str) -> str:
        return f"Denied: '{valve_name}' is set to False in Valves. Enable it to allow this action."

    def _headers(self) -> dict:
        h = {}
        if self.valves.auth_token:
            h["Authorization"] = f"Bearer {self.valves.auth_token}"
        return h

    def _err_detail(self, r) -> str:
        try:
            detail = r.json().get("detail", "")
        except Exception:
            detail = (r.text or "")[:300]
        if isinstance(detail, (dict, list)):
            return json.dumps(detail, ensure_ascii=False)
        return str(detail) or "no detail provided"

    def _get(self, path: str) -> str:
        try:
            r = httpx.get(f"{self.valves.manager_url}{path}", headers=self._headers(), timeout=10)
            if r.status_code == 401:
                return "Error: Authentication required. Set auth_token in Valves."
            if r.status_code == 403:
                return f"Error: Forbidden (403) — {self._err_detail(r)}"
            if r.status_code >= 400:
                return f"Error {r.status_code}: {self._err_detail(r)}"
            try:
                return json.dumps(r.json(), indent=2)
            except Exception:
                return r.text
        except httpx.ConnectError:
            return f"Error: Cannot connect to manager at {self.valves.manager_url}"
        except Exception as e:
            return f"Error: {type(e).__name__}: {e}" if str(e) else f"Error: {type(e).__name__}"

    def _post(self, path: str, data: dict = None) -> str:
        try:
            r = httpx.post(
                f"{self.valves.manager_url}{path}",
                headers=self._headers(),
                json=data or {},
                timeout=60
            )
            if r.status_code == 401:
                return "Error: Authentication required. Set auth_token in Valves."
            if r.status_code == 403:
                return f"Error: Forbidden (403) — {self._err_detail(r)}"
            if r.status_code >= 400:
                return f"Error {r.status_code}: {self._err_detail(r)}"
            try:
                return json.dumps(r.json(), indent=2)
            except Exception:
                return r.text
        except httpx.ConnectError:
            return f"Error: Cannot connect to manager at {self.valves.manager_url}"
        except Exception as e:
            return f"Error: {type(e).__name__}: {e}" if str(e) else f"Error: {type(e).__name__}"

    def _put(self, path: str, data: dict) -> str:
        try:
            r = httpx.put(
                f"{self.valves.manager_url}{path}",
                headers=self._headers(),
                json=data,
                timeout=10
            )
            if r.status_code == 401:
                return "Error: Authentication required. Set auth_token in Valves."
            if r.status_code == 403:
                return f"Error: Forbidden (403) — {self._err_detail(r)}"
            if r.status_code >= 400:
                return f"Error {r.status_code}: {self._err_detail(r)}"
            try:
                return json.dumps(r.json(), indent=2)
            except Exception:
                return r.text
        except httpx.ConnectError:
            return f"Error: Cannot connect to manager at {self.valves.manager_url}"
        except Exception as e:
            return f"Error: {type(e).__name__}: {e}" if str(e) else f"Error: {type(e).__name__}"

    def _delete(self, path: str) -> str:
        try:
            r = httpx.delete(
                f"{self.valves.manager_url}{path}",
                headers=self._headers(),
                timeout=10
            )
            if r.status_code == 401:
                return "Error: Authentication required. Set auth_token in Valves."
            if r.status_code == 403:
                return f"Error: Forbidden (403) — {self._err_detail(r)}"
            if r.status_code >= 400:
                return f"Error {r.status_code}: {self._err_detail(r)}"
            try:
                return json.dumps(r.json(), indent=2)
            except Exception:
                return r.text
        except httpx.ConnectError:
            return f"Error: Cannot connect to manager at {self.valves.manager_url}"
        except Exception as e:
            return f"Error: {type(e).__name__}: {e}" if str(e) else f"Error: {type(e).__name__}"

    def list_instances(self) -> str:
        """List all MCP server instances with their status, port and URL."""
        if not self.valves.allow_list_instances:
            return self._denied("allow_list_instances")
        return self._get("/api/instances")

    def get_instance(self, instance_id: str) -> str:
        """Get status and details of a specific MCP server instance.

        Args:
            instance_id: The instance ID (e.g. 'openhab', 'calculator')
        """
        if not self.valves.allow_get_instance:
            return self._denied("allow_get_instance")
        return self._get(f"/api/instances/{instance_id}")

    def start_instance(self, instance_id: str) -> str:
        """Start an MCP server instance.

        Args:
            instance_id: The instance ID to start
        """
        if not self.valves.allow_start:
            return self._denied("allow_start")
        return self._post(f"/api/instances/{instance_id}/start")

    def stop_instance(self, instance_id: str) -> str:
        """Stop a running MCP server instance.

        Args:
            instance_id: The instance ID to stop
        """
        if not self.valves.allow_stop:
            return self._denied("allow_stop")
        return self._post(f"/api/instances/{instance_id}/stop")

    def restart_instance(self, instance_id: str) -> str:
        """Restart an MCP server instance.

        Args:
            instance_id: The instance ID to restart
        """
        if not self.valves.allow_restart:
            return self._denied("allow_restart")
        return self._post(f"/api/instances/{instance_id}/restart")

    def reinstall_instance(self, instance_id: str) -> str:
        """Reinstall dependencies for an MCP server instance.

        Args:
            instance_id: The instance ID to reinstall
        """
        if not self.valves.allow_reinstall:
            return self._denied("allow_reinstall")
        return self._post(f"/api/instances/{instance_id}/reinstall")

    def get_install_log(self, instance_id: str) -> str:
        """Get the installation log for an MCP server instance.

        Args:
            instance_id: The instance ID
        """
        if not self.valves.allow_install_log:
            return self._denied("allow_install_log")
        return self._get(f"/api/instances/{instance_id}/logs/install")

    def get_runtime_log(self, instance_id: str) -> str:
        """Get the runtime log for an MCP server instance.

        Args:
            instance_id: The instance ID
        """
        if not self.valves.allow_runtime_log:
            return self._denied("allow_runtime_log")
        return self._get(f"/api/instances/{instance_id}/logs/runtime")

    def get_instance_config(self, instance_id: str) -> str:
        """Get the full configuration of an MCP server instance including values.

        Args:
            instance_id: The instance ID
        """
        if not self.valves.allow_get_config:
            return self._denied("allow_get_config")
        return self._get(f"/api/instances/{instance_id}/config")

    def get_settings(self) -> str:
        """Get current manager settings: auth status, edit mode, host, port and MCP token status."""
        if not self.valves.allow_get_settings:
            return self._denied("allow_get_settings")
        return self._get("/api/settings")

    def get_tool_code(self, instance_id: str) -> str:
        """Get the Python source code of an MCP server tool. Requires full edit mode.

        Args:
            instance_id: The instance ID
        """
        if not self.valves.allow_get_code:
            return self._denied("allow_get_code")
        return self._get(f"/api/instances/{instance_id}/tool-code")

    def save_tool_code(self, instance_id: str, code: str) -> str:
        """Replace the Python code of an EXISTING instance — this is the 'edit code' action.

        Use this (NOT upload_tool) whenever an instance with this ID already exists,
        e.g. to fix a bug, add a comment or add a method. The manager validates the
        code before saving and rejects invalid code with an error list. On success
        the instance restarts automatically, so the change is live immediately.
        Requires full edit mode.

        Args:
            instance_id: The instance ID whose code to replace
            code: The complete new Python source code (the full file, not a diff)
        """
        if not self.valves.allow_save_code:
            return self._denied("allow_save_code")
        return self._put(f"/api/instances/{instance_id}/tool-code", {"code": code})

    def validate_tool_code(self, code: str) -> str:
        """Validate Python tool code: syntax check, runtime inspection and schema generation.

        ALWAYS call this before upload_tool or save_tool_code and fix every reported
        error first — the manager rejects invalid code anyway, so validating early
        saves a round trip. Returns valid, errors, warnings, the generated tool
        specs and the Valves defaults. Requires full edit mode.

        Args:
            code: The Python source code to validate
        """
        if not self.valves.allow_validate_code:
            return self._denied("allow_validate_code")
        return self._post("/api/tools/validate", {"code": code})

    def export_tool(self, instance_id: str, name: str, description: str) -> str:
        """Export an MCP server tool as OpenWebUI-compatible JSON. Requires full edit mode.

        Args:
            instance_id: The instance ID (used as tool id)
            name: Display name for the exported tool
            description: Short description of the tool
        """
        if not self.valves.allow_export_tool:
            return self._denied("allow_export_tool")
        code_result = self._get(f"/api/instances/{instance_id}/tool-code")
        if code_result.startswith("Error"):
            return code_result
        try:
            code = json.loads(code_result)["code"]
        except (json.JSONDecodeError, KeyError):
            return "Error: Unexpected response format from tool-code endpoint"
        return self._post("/api/tools/export", {
            "code": code,
            "id": instance_id,
            "name": name,
            "description": description
        })

    def delete_instance(self, instance_id: str) -> str:
        """Delete an MCP server instance and its config. Requires upload or full edit mode.

        Args:
            instance_id: The instance ID to delete
        """
        if not self.valves.allow_delete:
            return self._denied("allow_delete")
        return self._delete(f"/api/instances/{instance_id}")

    def restart_manager(self) -> str:
        """Restart the json-mcp-manager process. The manager will come back up automatically."""
        if not self.valves.allow_manager_restart:
            return self._denied("allow_manager_restart")
        return self._post("/api/server/restart")

    def get_tool_template(self) -> str:
        """Returns the Python code template AND the complete JSON upload format.

        Always call this before writing or uploading a new tool.
        The response contains two sections:
        1. The Python code template (for the 'content' field in the upload JSON)
        2. The exact JSON array format that upload_tool() expects
        """
        if not self.valves.allow_get_template:
            return self._denied("allow_get_template")
        template = self._get("/api/tools/template")
        if template.startswith("Error"):
            return template
        json_example = json.dumps([
            {
                "id": "my_tool",
                "user_id": "00000000-0000-0000-0000-000000000000",
                "name": "My Tool",
                "meta": {
                    "description": "Short description shown in UI and to the AI",
                    "manifest": {
                        "title": "My Tool",
                        "author": "Your Name",
                        "version": "0.1.0"
                    }
                },
                "specs": [
                    {
                        "name": "my_function",
                        "description": "What this function does",
                        "parameters": {
                            "type": "object",
                            "properties": {
                                "param": {
                                    "type": "string",
                                    "description": "Description of this parameter"
                                }
                            },
                            "required": ["param"]
                        }
                    }
                ],
                "content": "# Replace this with the Python code from the template above"
            }
        ], indent=2)
        return (
            "=== PYTHON CODE TEMPLATE (use as 'content' field) ===\n\n"
            + template
            + "\n\n=== UPLOAD JSON FORMAT ===\n"
            + "upload_tool() expects a JSON array (not an object). Each element has:\n"
            + "  id       — unique snake_case identifier (becomes the MCP server ID)\n"
            + "  user_id  — always '00000000-0000-0000-0000-000000000000'\n"
            + "  name     — display name\n"
            + "  meta     — {description, manifest: {title, author, version}}\n"
            + "  specs    — list of tool definitions matching the methods in your Tools class\n"
            + "  content  — the complete Python source code as a string\n\n"
            + "Example:\n"
            + json_example
        )

    def upload_tool(self, json_content: str) -> str:
        """Create and install a NEW tool instance from a JSON definition.

        Only for NEW tools: fails if the ID already exists — in that case use
        save_tool_code(instance_id, code) to change the existing tool instead.
        The manager validates the Python code on upload and rejects invalid code
        with an error list. Requires upload or full edit mode.

        Workflow for a new tool:
        1. get_tool_template() — get the exact JSON format and code template
        2. validate_tool_code(code) — repeat until there are no errors
        3. upload_tool(json_content) — json_content must be a JSON ARRAY (not an object)
        4. start_instance(id) — uploaded instances do not start automatically

        Args:
            json_content: JSON array string — call get_tool_template() to see the format
        """
        if not self.valves.allow_upload:
            return self._denied("allow_upload")
        try:
            json.loads(json_content)
        except json.JSONDecodeError:
            return "Error: Invalid JSON content provided"
        try:
            headers = {}
            if self.valves.auth_token:
                headers["Authorization"] = f"Bearer {self.valves.auth_token}"
            r = httpx.post(
                f"{self.valves.manager_url}/api/instances/upload",
                headers=headers,
                files={"file": ("tool.json", json_content.encode(), "application/json")},
                timeout=120
            )
            if r.status_code == 401:
                return "Error: Authentication required. Set auth_token in Valves."
            if r.status_code == 403:
                return f"Error: Forbidden (403) — {self._err_detail(r)}"
            if r.status_code >= 400:
                return f"Error {r.status_code}: {self._err_detail(r)}"
            return json.dumps(r.json(), indent=2)
        except httpx.ConnectError:
            return f"Error: Cannot connect to manager at {self.valves.manager_url}"
        except Exception as e:
            return f"Error: {type(e).__name__}: {e}" if str(e) else f"Error: {type(e).__name__}"

    def create_tool(self, code: str, id: str, name: str = "", description: str = "", requirements: str = "", venv: str = "default", port: int = 0) -> str:
        """Create and install a NEW instance from raw Python code in ONE step.

        Preferred over upload_tool: pass the plain Python source (no JSON
        wrapping, no specs). The manager installs dependencies, validates the
        code in the instance's venv, fills the Valve defaults into the editable
        config and saves it. Dependencies come from the `requirements:` line in
        the code's docstring, or pass them explicitly as a comma-separated
        string. The new instance does NOT auto-start — call start_instance(id)
        afterwards. Fails if the ID already exists (use save_tool_code to modify
        an existing tool). Requires upload or full edit mode.

        Args:
            code: The complete Python source code (the full file)
            id: Unique snake_case identifier (becomes the MCP server ID)
            name: Display name (defaults to the ID)
            description: Short description shown in the UI and to the AI
            requirements: Optional comma-separated pip packages (overrides the docstring)
            venv: Virtual-env name to install into (default: "default")
            port: Optional fixed port (1024-65535); omit/0 to auto-assign
        """
        if not self.valves.allow_create_tool:
            return self._denied("allow_create_tool")
        body = {"id": id, "code": code, "name": name, "description": description, "venv": venv}
        if requirements and requirements.strip():
            body["requirements"] = requirements
        if port:
            body["port"] = port
        return self._post("/api/tools/create", body)

    def update_instance_values(self, instance_id: str, values: dict) -> str:
        """Set/merge Valve values (configuration) of an existing instance.

        Merges the given keys into the instance's editable config values, e.g.
        an API key or a base URL. Other values are kept (send only the keys you
        want to change). Requires upload or full edit mode.

        IMPORTANT: the new values are written to the config but do NOT take
        effect until the instance is restarted. This tool does NOT restart on
        its own. After a successful change, ASK THE USER whether to restart the
        instance now, and only then call restart_instance(instance_id).

        Args:
            instance_id: The instance ID to update
            values: Mapping of valve name to value (only the keys to change)
        """
        if not self.valves.allow_update_values:
            return self._denied("allow_update_values")
        result = self._put(f"/api/instances/{instance_id}", {"values": values})
        if result.startswith("Error"):
            return result
        return (
            result
            + "\n\nValues saved. They only take effect after a restart — this tool "
            + "did not restart the instance. Ask the user whether to restart '"
            + instance_id + "' now, then call restart_instance('" + instance_id
            + "') only if they agree."
        )

    def update_instance_dependencies(self, instance_id: str, dependencies: list) -> str:
        """Replace the pip dependencies of an existing instance and reinstall them.

        Sets install.dependencies to the given list and triggers a reinstall
        into the instance's venv. Requires upload or full edit mode.

        Args:
            instance_id: The instance ID to update
            dependencies: Full list of pip package specs (replaces the old list)
        """
        if not self.valves.allow_update_dependencies:
            return self._denied("allow_update_dependencies")
        set_result = self._put(f"/api/instances/{instance_id}", {"install": {"dependencies": dependencies}})
        if set_result.startswith("Error"):
            return set_result
        return self._post(f"/api/instances/{instance_id}/reinstall")

    def update_instance_venv(self, instance_id: str, venv: str) -> str:
        """Move an instance to a different virtual environment (venv).

        Sets the instance's venv, (re)installs its dependencies there and — if the
        instance is running — restarts it so the change applies immediately. The
        target venv is created automatically if it does not exist yet. Requires
        upload or full edit mode.

        Args:
            instance_id: The instance ID to move
            venv: Target venv name (created on demand; letters, digits, _ and -)
        """
        if not self.valves.allow_update_venv:
            return self._denied("allow_update_venv")
        return self._put(f"/api/instances/{instance_id}", {"venv": venv})
